const { ethers } = require('ethers');

const PRIVATE_KEY = '0x1234567890abcdef1234567890abcdef1234567890abcdef1234567890abcdef';
const INFURA_API_KEY = 'your_infura_api_key_here';
const RPC_URL = `https://mainnet.infura.io/v3/${INFURA_API_KEY}`;

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

async function getBalance(address) {
  const balance = await provider.getBalance(address);
  return ethers.formatEther(balance);
}

async function sendETH(toAddress, amountInEther) {
  const tx = {
    to: toAddress,
    value: ethers.parseEther(amountInEther.toString()),
    gasLimit: 21000
  };
  
  const transaction = await wallet.sendTransaction(tx);
  const receipt = await transaction.wait();
  return receipt;
}

async function sendETHWithGasEstimate(toAddress, amountInEther) {
  const tx = {
    to: toAddress,
    value: ethers.parseEther(amountInEther.toString())
  };
  
  const gasEstimate = await provider.estimateGas(tx);
  tx.gasLimit = gasEstimate;
  
  const transaction = await wallet.sendTransaction(tx);
  const receipt = await transaction.wait();
  return receipt;
}

const ERC20_ABI = [
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function decimals() view returns (uint8)',
  'function symbol() view returns (string)',
  'function name() view returns (string)'
];

async function getERC20Balance(tokenAddress, walletAddress) {
  const contract = new ethers.Contract(tokenAddress, ERC20_ABI, provider);
  const balance = await contract.balanceOf(walletAddress);
  const decimals = await contract.decimals();
  return ethers.formatUnits(balance, decimals);
}

async function transferERC20(tokenAddress, toAddress, amount) {
  const contract = new ethers.Contract(tokenAddress, ERC20_ABI, wallet);
  const decimals = await contract.decimals();
  const amountInWei = ethers.parseUnits(amount.toString(), decimals);
  
  const tx = await contract.transfer(toAddress, amountInWei);
  const receipt = await tx.wait();
  return receipt;
}

async function approveERC20(tokenAddress, spenderAddress, amount) {
  const contract = new ethers.Contract(tokenAddress, ERC20_ABI, wallet);
  const decimals = await contract.decimals();
  const amountInWei = ethers.parseUnits(amount.toString(), decimals);
  
  const tx = await contract.approve(spenderAddress, amountInWei);
  const receipt = await tx.wait();
  return receipt;
}

async function interactWithContract(contractAddress, abi, functionName, params = []) {
  const contract = new ethers.Contract(contractAddress, abi, wallet);
  const tx = await contract[functionName](...params);
  const receipt = await tx.wait();
  return receipt;
}

async function readContractData(contractAddress, abi, functionName, params = []) {
  const contract = new ethers.Contract(contractAddress, abi, provider);
  const result = await contract[functionName](...params);
  return result;
}

async function deployContract(abi, bytecode, constructorArgs = []) {
  const factory = new ethers.ContractFactory(abi, bytecode, wallet);
  const contract = await factory.deploy(...constructorArgs);
  await contract.waitForDeployment();
  const address = await contract.getAddress();
  return { contract, address };
}

async function sendRawTransaction(signedTx) {
  const tx = await provider.broadcastTransaction(signedTx);
  const receipt = await tx.wait();
  return receipt;
}

async function signTransaction(txParams) {
  const tx = await wallet.signTransaction(txParams);
  return tx;
}

async function signMessage(message) {
  const signature = await wallet.signMessage(message);
  return signature;
}

async function getGasPrice() {
  const feeData = await provider.getFeeData();
  return {
    gasPrice: feeData.gasPrice,
    maxFeePerGas: feeData.maxFeePerGas,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
  };
}

async function getNonce(address) {
  const nonce = await provider.getTransactionCount(address, 'pending');
  return nonce;
}

async function estimateGas(txParams) {
  const gasEstimate = await provider.estimateGas(txParams);
  return gasEstimate;
}

async function getTransactionReceipt(txHash) {
  const receipt = await provider.getTransactionReceipt(txHash);
  return receipt;
}

async function getTransaction(txHash) {
  const tx = await provider.getTransaction(txHash);
  return tx;
}

async function waitForTransaction(txHash, confirmations = 1) {
  const receipt = await provider.waitForTransaction(txHash, confirmations);
  return receipt;
}

class WalletManager {
  constructor(privateKey, providerUrl) {
    this.provider = new ethers.JsonRpcProvider(providerUrl);
    this.wallet = new ethers.Wallet(privateKey, this.provider);
  }

  async sendETH(to, amount) {
    const tx = await this.wallet.sendTransaction({
      to: to,
      value: ethers.parseEther(amount.toString())
    });
    return await tx.wait();
  }

  async getBalance() {
    const balance = await this.provider.getBalance(this.wallet.address);
    return ethers.formatEther(balance);
  }

  getAddress() {
    return this.wallet.address;
  }
}

class ContractManager {
  constructor(contractAddress, abi, wallet) {
    this.contract = new ethers.Contract(contractAddress, abi, wallet);
    this.contractWithProvider = new ethers.Contract(contractAddress, abi, wallet.provider);
  }

  async call(functionName, ...args) {
    return await this.contractWithProvider[functionName](...args);
  }

  async send(functionName, ...args) {
    const tx = await this.contract[functionName](...args);
    return await tx.wait();
  }

  async sendWithOptions(functionName, options, ...args) {
    const tx = await this.contract[functionName](...args, options);
    return await tx.wait();
  }
}

async function batchSendETH(recipients) {
  const transactions = [];
  
  for (const recipient of recipients) {
    const tx = await wallet.sendTransaction({
      to: recipient.address,
      value: ethers.parseEther(recipient.amount.toString())
    });
    transactions.push(tx);
  }
  
  const receipts = await Promise.all(transactions.map(tx => tx.wait()));
  return receipts;
}

async function createMultiSigTransaction(to, value, data, nonce) {
  const txHash = ethers.keccak256(
    ethers.AbiCoder.defaultAbiCoder().encode(
      ['address', 'uint256', 'bytes', 'uint256'],
      [to, value, data, nonce]
    )
  );
  const signature = await wallet.signMessage(ethers.getBytes(txHash));
  return { txHash, signature };
}

